            { "question": "Adequate coping mechanisms mean:", "options": ["Random responses with no effect", "Behavioral strategies that have worked before", "Ignoring the problem", "Avoiding all emotions"], "answer": "Behavioral strategies that have worked before" },
            { "question": "Which is an example of a maturational crisis?", "options": ["Divorce", "Flood", "Retirement", "Earthquake"], "answer": "Retirement" },
