            { "question": "Crisis intervention is best defined as:", "options": ["A long-term treatment plan", "A brief, focused, and time-limited treatment strategy", "A surgical procedure", "A diagnosis only"], "answer": "A brief, focused, and time-limited treatment strategy" },
            { "question": "Catharsis means:", "options": ["Punishing behavior", "Release of feelings while the patient talks", "Ignoring emotions", "Ending the interview immediately"], "answer": "Release of feelings while the patient talks" },
