            { "question": "Suggestion means:", "options": ["Forcing the patient to comply", "Influencing the patient to accept an idea or belief", "Ignoring the patient", "Giving punishment"], "answer": "Influencing the patient to accept an idea or belief" },
            { "question": "Reinforcement of behavior means:", "options": ["Giving positive responses to adaptive behavior", "Ignoring improvement", "Punishing good behavior", "Encouraging dependency"], "answer": "Giving positive responses to adaptive behavior" },
