            { "question": "Environmental manipulation means:", "options": ["Changing the patient’s physical or interpersonal situation", "Giving punishment", "Ignoring the crisis", "Isolating permanently"], "answer": "Changing the patient’s physical or interpersonal situation" },
            { "question": "General support includes:", "options": ["Warmth, acceptance, empathy, and reassurance", "Judgment and criticism", "Silence only", "Punishment"], "answer": "Warmth, acceptance, empathy, and reassurance" },
