            { "question": "During crisis intervention, the nurse should help the individual:", "options": ["Avoid all support systems", "Identify external support systems and new social networks", "Depend only on the nurse", "Stop communicating"], "answer": "Identify external support systems and new social networks" },
            { "question": "In the evaluation phase, the nurse asks whether the individual:", "options": ["Has positive behavioral changes and adaptive coping strategies", "Wants to isolate forever", "Forgot the event completely", "Refuses all support"], "answer": "Has positive behavioral changes and adaptive coping strategies" },
            { "question": "A mobile crisis program mainly provides:", "options": ["Home exercise only", "On-site assessment, treatment, referral, and crisis management", "Surgery", "Long-term hospitalization only"], "answer": "On-site assessment, treatment, referral, and crisis management" },
            { "question": "Telephone crisis intervention requires:", "options": ["No listening skills", "Effective listening skills", "Physical examination", "Medication only"], "answer": "Effective listening skills" },
            { "question": "Group work in crisis intervention helps by:", "options": ["Increasing isolation", "Fostering hope and mutual support", "Creating competition", "Preventing expression"], "answer": "Fostering hope and mutual support" },
